1109 /// Fold a divide or remainder with a select instruction divisor when one of the
1110 /// select operands is zero. In that case, we can use the other select operand
1111 /// because div/rem by zero is undefined.
1112 bool InstCombinerImpl::simplifyDivRemOfSelectWithZeroOp(BinaryOperator &I) {
1113   SelectInst *SI = dyn_cast<SelectInst>(I.getOperand(1));
1114   if (!SI)
1115     return false;
1116 
1117   int NonNullOperand;
1118   if (match(SI->getTrueValue(), m_Zero()))
1119     // div/rem X, (Cond ? 0 : Y) -> div/rem X, Y
1120     NonNullOperand = 2;
1121   else if (match(SI->getFalseValue(), m_Zero()))
1122     // div/rem X, (Cond ? Y : 0) -> div/rem X, Y
1123     NonNullOperand = 1;
1124   else
1125     return false;
1126 
1127   // Change the div/rem to use 'Y' instead of the select.
1128   replaceOperand(I, 1, SI->getOperand(NonNullOperand));
1129 
1130   // Okay, we know we replace the operand of the div/rem with 'Y' with no
1131   // problem.  However, the select, or the condition of the select may have
1132   // multiple uses.  Based on our knowledge that the operand must be non-zero,
1133   // propagate the known value for the select into other uses of it, and
1134   // propagate a known value of the condition into its other users.
1135 
1136   // If the select and condition only have a single use, don't bother with this,
1137   // early exit.
1138   Value *SelectCond = SI->getCondition();
1139   if (SI->use_empty() && SelectCond->hasOneUse())
1140     return true;
1141 
1142   // Scan the current block backward, looking for other uses of SI.
1143   BasicBlock::iterator BBI = I.getIterator(), BBFront = I.getParent()->begin();
1144   Type *CondTy = SelectCond->getType();
1145   while (BBI != BBFront) {
1146     --BBI;
1147     // If we found an instruction that we can't assume will return, so
1148     // information from below it cannot be propagated above it.
1149     if (!isGuaranteedToTransferExecutionToSuccessor(&*BBI))
1150       break;
1151 
1152     // Replace uses of the select or its condition with the known values.
1153     for (Use &Op : BBI->operands()) {
1154       if (Op == SI) {
1155         replaceUse(Op, SI->getOperand(NonNullOperand));
1156         Worklist.push(&*BBI);
1157       } else if (Op == SelectCond) {
1158         replaceUse(Op, NonNullOperand == 1 ? ConstantInt::getTrue(CondTy)
1159                                            : ConstantInt::getFalse(CondTy));
1160         Worklist.push(&*BBI);
1161       }
1162     }
1163 
1164     // If we past the instruction, quit looking for it.
1165     if (&*BBI == SI)
1166       SI = nullptr;
1167     if (&*BBI == SelectCond)
1168       SelectCond = nullptr;
1169 
1170     // If we ran out of things to eliminate, break out of the loop.
1171     if (!SelectCond && !SI)
1172       break;
1173 
1174   }
1175   return true;
1176 }
