1186 /// True if C1 is a multiple of C2. Quotient contains C1/C2.
1187 static bool isMultiple(const APInt &C1, const APInt &C2, APInt &Quotient,
1188                        bool IsSigned) {
1189   assert(C1.getBitWidth() == C2.getBitWidth() && "Constant widths not equal");
1190 
1191   // Bail if we will divide by zero.
1192   if (C2.isZero())
1193     return false;
1194 
1195   // Bail if we would divide INT_MIN by -1.
1196   if (IsSigned && C1.isMinSignedValue() && C2.isAllOnes())
1197     return false;
1198 
1199   APInt Remainder(C1.getBitWidth(), /*val=*/0ULL, IsSigned);
1200   if (IsSigned)
1201     APInt::sdivrem(C1, C2, Quotient, Remainder);
1202   else
1203     APInt::udivrem(C1, C2, Quotient, Remainder);
1204 
1205   return Remainder.isMinValue();
1206 }
