1208 static Value *foldIDivShl(BinaryOperator &I, InstCombiner::BuilderTy &Builder) {
1209   assert((I.getOpcode() == Instruction::SDiv ||
1210           I.getOpcode() == Instruction::UDiv) &&
1211          "Expected integer divide");
1212 
1213   bool IsSigned = I.getOpcode() == Instruction::SDiv;
1214   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
1215   Type *Ty = I.getType();
1216 
1217   Value *X, *Y, *Z;
1218 
1219   // With appropriate no-wrap constraints, remove a common factor in the
1220   // dividend and divisor that is disguised as a left-shifted value.
1221   if (match(Op1, m_Shl(m_Value(X), m_Value(Z))) &&
1222       match(Op0, m_c_Mul(m_Specific(X), m_Value(Y)))) {
1223     // Both operands must have the matching no-wrap for this kind of division.
1224     auto *Mul = cast<OverflowingBinaryOperator>(Op0);
1225     auto *Shl = cast<OverflowingBinaryOperator>(Op1);
1226     bool HasNUW = Mul->hasNoUnsignedWrap() && Shl->hasNoUnsignedWrap();
1227     bool HasNSW = Mul->hasNoSignedWrap() && Shl->hasNoSignedWrap();
1228 
1229     // (X * Y) u/ (X << Z) --> Y u>> Z
1230     if (!IsSigned && HasNUW)
1231       return Builder.CreateLShr(Y, Z, "", I.isExact());
1232 
1233     // (X * Y) s/ (X << Z) --> Y s/ (1 << Z)
1234     if (IsSigned && HasNSW && (Op0->hasOneUse() || Op1->hasOneUse())) {
1235       Value *Shl = Builder.CreateShl(ConstantInt::get(Ty, 1), Z);
1236       return Builder.CreateSDiv(Y, Shl, "", I.isExact());
1237     }
1238   }
1239 
1240   // With appropriate no-wrap constraints, remove a common factor in the
1241   // dividend and divisor that is disguised as a left-shift amount.
1242   if (match(Op0, m_Shl(m_Value(X), m_Value(Z))) &&
1243       match(Op1, m_Shl(m_Value(Y), m_Specific(Z)))) {
1244     auto *Shl0 = cast<OverflowingBinaryOperator>(Op0);
1245     auto *Shl1 = cast<OverflowingBinaryOperator>(Op1);
1246 
1247     // For unsigned div, we need 'nuw' on both shifts or
1248     // 'nsw' on both shifts + 'nuw' on the dividend.
1249     // (X << Z) / (Y << Z) --> X / Y
1250     if (!IsSigned &&
1251         ((Shl0->hasNoUnsignedWrap() && Shl1->hasNoUnsignedWrap()) ||
1252          (Shl0->hasNoUnsignedWrap() && Shl0->hasNoSignedWrap() &&
1253           Shl1->hasNoSignedWrap())))
1254       return Builder.CreateUDiv(X, Y, "", I.isExact());
1255 
1256     // For signed div, we need 'nsw' on both shifts + 'nuw' on the divisor.
1257     // (X << Z) / (Y << Z) --> X / Y
1258     if (IsSigned && Shl0->hasNoSignedWrap() && Shl1->hasNoSignedWrap() &&
1259         Shl1->hasNoUnsignedWrap())
1260       return Builder.CreateSDiv(X, Y, "", I.isExact());
1261   }
1262 
1263   // If X << Y and X << Z does not overflow, then:
1264   // (X << Y) / (X << Z) -> (1 << Y) / (1 << Z) -> 1 << Y >> Z
1265   if (match(Op0, m_Shl(m_Value(X), m_Value(Y))) &&
1266       match(Op1, m_Shl(m_Specific(X), m_Value(Z)))) {
1267     auto *Shl0 = cast<OverflowingBinaryOperator>(Op0);
1268     auto *Shl1 = cast<OverflowingBinaryOperator>(Op1);
1269 
1270     if (IsSigned ? (Shl0->hasNoSignedWrap() && Shl1->hasNoSignedWrap())
1271                  : (Shl0->hasNoUnsignedWrap() && Shl1->hasNoUnsignedWrap())) {
1272       Constant *One = ConstantInt::get(X->getType(), 1);
1273       // Only preserve the nsw flag if dividend has nsw
1274       // or divisor has nsw and operator is sdiv.
1275       Value *Dividend = Builder.CreateShl(
1276           One, Y, "shl.dividend",
1277           /*HasNUW=*/true,
1278           /*HasNSW=*/
1279           IsSigned ? (Shl0->hasNoUnsignedWrap() || Shl1->hasNoUnsignedWrap())
1280                    : Shl0->hasNoSignedWrap());
1281       return Builder.CreateLShr(Dividend, Z, "", I.isExact());
1282     }
1283   }
1284 
1285   return nullptr;
1286 }
