2285 // Variety of transform for:
2286 //  (urem/srem (mul X, Y), (mul X, Z))
2287 //  (urem/srem (shl X, Y), (shl X, Z))
2288 //  (urem/srem (shl Y, X), (shl Z, X))
2289 // NB: The shift cases are really just extensions of the mul case. We treat
2290 // shift as Val * (1 << Amt).
2291 static Instruction *simplifyIRemMulShl(BinaryOperator &I,
2292                                        InstCombinerImpl &IC) {
2293   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1), *X = nullptr;
2294   APInt Y, Z;
2295   bool ShiftByX = false;
2296 
2297   // If V is not nullptr, it will be matched using m_Specific.
2298   auto MatchShiftOrMulXC = [](Value *Op, Value *&V, APInt &C,
2299                               bool &PreserveNSW) -> bool {
2300     const APInt *Tmp = nullptr;
2301     if ((!V && match(Op, m_Mul(m_Value(V), m_APInt(Tmp)))) ||
2302         (V && match(Op, m_Mul(m_Specific(V), m_APInt(Tmp)))))
2303       C = *Tmp;
2304     else if ((!V && match(Op, m_Shl(m_Value(V), m_APInt(Tmp)))) ||
2305              (V && match(Op, m_Shl(m_Specific(V), m_APInt(Tmp))))) {
2306       C = APInt(Tmp->getBitWidth(), 1) << *Tmp;
2307       // We cannot preserve NSW when shifting by BW - 1.
2308       PreserveNSW = Tmp->ult(Tmp->getBitWidth() - 1);
2309     }
2310     if (Tmp != nullptr)
2311       return true;
2312 
2313     // Reset `V` so we don't start with specific value on next match attempt.
2314     V = nullptr;
2315     return false;
2316   };
2317 
2318   auto MatchShiftCX = [](Value *Op, APInt &C, Value *&V) -> bool {
2319     const APInt *Tmp = nullptr;
2320     if ((!V && match(Op, m_Shl(m_APInt(Tmp), m_Value(V)))) ||
2321         (V && match(Op, m_Shl(m_APInt(Tmp), m_Specific(V))))) {
2322       C = *Tmp;
2323       return true;
2324     }
2325 
2326     // Reset `V` so we don't start with specific value on next match attempt.
2327     V = nullptr;
2328     return false;
2329   };
