1995 static Instruction *foldFDivPowDivisor(BinaryOperator &I,
1996                                        InstCombiner::BuilderTy &Builder) {
1997   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
1998   auto *II = dyn_cast<IntrinsicInst>(Op1);
1999   if (!II || !II->hasOneUse() || !I.hasAllowReassoc() ||
2000       !I.hasAllowReciprocal() || !II->hasAllowReassoc())
2001     return nullptr;
2002 
2003   // Z / pow(X, Y) --> Z  * (1 / pow(X, Y)) --> Z * pow(X, -Y)
2004   // Z / exp{2}(Y) --> Z * (1 / exp{2}(Y)) --> Z * exp{2}(-Y)
2005   // In the general case, this creates an extra instruction, but fmul allows
2006   // for better canonicalization and optimization than fdiv.
2007   Intrinsic::ID IID = II->getIntrinsicID();
2008   SmallVector<Value *> Args;
2009   switch (IID) {
2010   case Intrinsic::pow:
2011     Args.push_back(II->getArgOperand(0));
2012     Args.push_back(Builder.CreateFNegFMF(II->getArgOperand(1), &I));
2013     break;
2014   case Intrinsic::powi: {
2015     // Require 'ninf' assuming that makes powi(X, -INT_MIN) acceptable.
2016     // That is, X ** (huge negative number) is 0.0, ~1.0, or INF and so
2017     // dividing by that is INF, ~1.0, or 0.0. Code that uses powi allows
2018     // non-standard results, so this corner case should be acceptable if the
2019     // code rules out INF values.
2020     if (!I.hasNoInfs())
2021       return nullptr;
2022     Args.push_back(II->getArgOperand(0));
2023     Args.push_back(Builder.CreateNeg(II->getArgOperand(1)));
2024     Type *Tys[] = {I.getType(), II->getArgOperand(1)->getType()};
2025     Value *Pow = Builder.CreateIntrinsic(IID, Tys, Args, &I);
2026     return BinaryOperator::CreateFMulFMF(Op0, Pow, &I);
2027   }
2028   case Intrinsic::exp:
2029   case Intrinsic::exp2:
2030     Args.push_back(Builder.CreateFNegFMF(II->getArgOperand(0), &I));
2031     break;
2032   default:
2033     return nullptr;
2034   }
2035   Value *Pow = Builder.CreateIntrinsic(IID, I.getType(), Args, &I);
2036   return BinaryOperator::CreateFMulFMF(Op0, Pow, &I);
2037 }
