2039 /// Convert div to mul if we have an sqrt divisor iff sqrt's operand is a fdiv
2040 /// instruction.
2041 static Instruction *foldFDivSqrtDivisor(BinaryOperator &I,
2042                                         InstCombiner::BuilderTy &Builder) {
2043   // X / sqrt(Y / Z) --> X * (1 / (sqrt(Y / Z))) -->
2044   // X * (1 / sqrt(Y * (1 / Z))) -> X * (1 / (sqrt(Y) * sqrt(1 / Z))) -->
2045   // X * ((1 / sqrt(Y)) * (1 / sqrt(1 / Z))) --> X * sqrt(Z / Y)
2046   if (!I.hasAllowReassoc() || !I.hasAllowReciprocal())
2047     return nullptr;
2048   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
2049   auto *II = dyn_cast<IntrinsicInst>(Op1);
2050   if (!II || II->getIntrinsicID() != Intrinsic::sqrt || !II->hasOneUse() ||
2051       !II->hasAllowReassoc())
2052     return nullptr;
2053 
2054   Value *Y, *Z;
2055   auto *DivOp = dyn_cast<Instruction>(II->getOperand(0));
2056   if (!DivOp || !match(DivOp, m_FDiv(m_Value(Y), m_Value(Z))) ||
2057       !DivOp->hasAllowReciprocal() || !DivOp->hasAllowReassoc() ||
2058       !DivOp->hasOneUse())
2059     return nullptr;
2060   Value *SwapDiv = Builder.CreateFDivFMF(Z, Y, DivOp);
2061   Value *NewSqrt =
2062       Builder.CreateUnaryIntrinsic(II->getIntrinsicID(), SwapDiv, II);
2063   return BinaryOperator::CreateFMulFMF(Op0, NewSqrt, &I);
2064 }
