2067 // X = 1/sqrt(a)
2068 // R1 = X * X
2069 // R2 = a * X
2070 //
2071 // TO
2072 //
2073 // FDiv = 1/a
2074 // FSqrt = sqrt(a)
2075 // FMul = FDiv * FSqrt
2076 // Replace Uses Of R1 With FDiv
2077 // Replace Uses Of R2 With FSqrt
2078 // Replace Uses Of X With FMul
2079 static Instruction *
2080 convertFSqrtDivIntoFMul(CallInst *CI, Instruction *X,
2081                         const SmallPtrSetImpl<Instruction *> &R1,
2082                         const SmallPtrSetImpl<Instruction *> &R2,
2083                         InstCombiner::BuilderTy &B, InstCombinerImpl *IC) {
2084 
2085   B.SetInsertPoint(X);
2086 
2087   // Have an instruction that is representative of all of instructions in R1 and
2088   // get the most common fpmath metadata and fast-math flags on it.
2089   Value *SqrtOp = CI->getArgOperand(0);
