2091       B.CreateFDiv(ConstantFP::get(X->getType(), 1.0), SqrtOp));
2092   auto *R1FPMathMDNode = (*R1.begin())->getMetadata(LLVMContext::MD_fpmath);
2093   FastMathFlags R1FMF = (*R1.begin())->getFastMathFlags(); // Common FMF
2094   for (Instruction *I : R1) {
2095     R1FPMathMDNode = MDNode::getMostGenericFPMath(
2096         R1FPMathMDNode, I->getMetadata(LLVMContext::MD_fpmath));
2097     R1FMF &= I->getFastMathFlags();
2098     IC->replaceInstUsesWith(*I, FDiv);
2099     IC->eraseInstFromFunction(*I);
2100   }
2101   FDiv->setMetadata(LLVMContext::MD_fpmath, R1FPMathMDNode);
2102   FDiv->copyFastMathFlags(R1FMF);
2103 
2104   // Have a single sqrt call instruction that is representative of all of
2105   // instructions in R2 and get the most common fpmath metadata and fast-math
2106   // flags on it.
2107   auto *FSqrt = cast<CallInst>(CI->clone());
2108   FSqrt->insertBefore(CI->getIterator());
2109   auto *R2FPMathMDNode = (*R2.begin())->getMetadata(LLVMContext::MD_fpmath);
2110   FastMathFlags R2FMF = (*R2.begin())->getFastMathFlags(); // Common FMF
2111   for (Instruction *I : R2) {
2112     R2FPMathMDNode = MDNode::getMostGenericFPMath(
2113         R2FPMathMDNode, I->getMetadata(LLVMContext::MD_fpmath));
2114     R2FMF &= I->getFastMathFlags();
2115     IC->replaceInstUsesWith(*I, FSqrt);
2116     IC->eraseInstFromFunction(*I);
2117   }
2118   FSqrt->setMetadata(LLVMContext::MD_fpmath, R2FPMathMDNode);
2119   FSqrt->copyFastMathFlags(R2FMF);
2120 
2121   Instruction *FMul;
2122   // If X = -1/sqrt(a) initially,then FMul = -(FDiv * FSqrt)
2123   if (match(X, m_FDiv(m_SpecificFP(-1.0), m_Specific(CI)))) {
2124     Value *Mul = B.CreateFMul(FDiv, FSqrt);
2125     FMul = cast<Instruction>(B.CreateFNeg(Mul));
2126   } else
2127     FMul = cast<Instruction>(B.CreateFMul(FDiv, FSqrt));
